import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Product Terminology","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/product/terminology.md","filePath":"sovereign-os/product/terminology.md"}'),i={name:"sovereign-os/product/terminology.md"};function n(s,e,l,c,p,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="product-terminology" tabindex="-1">Product Terminology <a class="header-anchor" href="#product-terminology" aria-label="Permalink to &quot;Product Terminology&quot;">​</a></h1><p><strong>Status:</strong> Draft<br><strong>Version:</strong> 0.1</p><h2 id="sovereign-home-os" tabindex="-1">Sovereign Home OS <a class="header-anchor" href="#sovereign-home-os" aria-label="Permalink to &quot;Sovereign Home OS&quot;">​</a></h2><p>The complete independent product: a local-first platform that provides a coherent interface, AI orchestration, permissions, capabilities, and lifecycle management around user-owned services.</p><p>It is not dependent on the separate Sovereign project, even when both projects share development practices or organizational ownership.</p><h2 id="core-platform" tabindex="-1">Core Platform <a class="header-anchor" href="#core-platform" aria-label="Permalink to &quot;Core Platform&quot;">​</a></h2><p>The trusted services responsible for configuration, identity, permissions, capability registration, plugin lifecycle, secrets, diagnostics, and other platform-wide concerns.</p><h2 id="ai-orchestration" tabindex="-1">AI Orchestration <a class="header-anchor" href="#ai-orchestration" aria-label="Permalink to &quot;AI Orchestration&quot;">​</a></h2><p>The bounded process that interprets a user request, selects from registered capabilities, validates proposed inputs, invokes allowed operations, and presents results. It is not unrestricted agency over the host.</p><h2 id="capability" tabindex="-1">Capability <a class="header-anchor" href="#capability" aria-label="Permalink to &quot;Capability&quot;">​</a></h2><p>A named, typed operation exposed to platform clients and AI orchestration. A capability defines inputs, outputs, permissions, side effects, errors, and a human-readable purpose. Example: <code>dns.stats.read</code>.</p><h2 id="capability-provider" tabindex="-1">Capability Provider <a class="header-anchor" href="#capability-provider" aria-label="Permalink to &quot;Capability Provider&quot;">​</a></h2><p>A component that implements one or more capabilities. Multiple providers may eventually implement the same capability contract.</p><h2 id="plugin" tabindex="-1">Plugin <a class="header-anchor" href="#plugin" aria-label="Permalink to &quot;Plugin&quot;">​</a></h2><p>An independently managed package that integrates a domain or service with the platform. A plugin declares its capabilities, permissions, configuration, health, and lifecycle metadata.</p><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><p>The connection between Sovereign Home OS and an external or separately managed service. During the preview, the Pi-hole integration may be built into the monorepo before a general plugin lifecycle exists.</p><h2 id="adapter" tabindex="-1">Adapter <a class="header-anchor" href="#adapter" aria-label="Permalink to &quot;Adapter&quot;">​</a></h2><p>Implementation code that translates a service-specific API into platform capability inputs, outputs, and errors.</p><h2 id="local-first" tabindex="-1">Local-First <a class="header-anchor" href="#local-first" aria-label="Permalink to &quot;Local-First&quot;">​</a></h2><p>Core useful behavior runs on user-owned hardware and remains available without an internet connection wherever reasonably possible. Optional remote services must be explicit and replaceable.</p><h2 id="privacy-first" tabindex="-1">Privacy-First <a class="header-anchor" href="#privacy-first" aria-label="Permalink to &quot;Privacy-First&quot;">​</a></h2><p>The system minimizes collection, storage, and transmission by default. Privacy is a design constraint, not a paid feature.</p><h2 id="preview" tabindex="-1">Preview <a class="header-anchor" href="#preview" aria-label="Permalink to &quot;Preview&quot;">​</a></h2><p>The first constrained proof on the project&#39;s target Raspberry Pi. It validates a complete experience but is not a production-ready public release.</p><h2 id="voice-satellite" tabindex="-1">Voice Satellite <a class="header-anchor" href="#voice-satellite" aria-label="Permalink to &quot;Voice Satellite&quot;">​</a></h2><p>A future lightweight endpoint for audio capture, playback, mute controls, and status indication. Reasoning and service integrations remain centralized on the home server.</p><h2 id="supported" tabindex="-1">Supported <a class="header-anchor" href="#supported" aria-label="Permalink to &quot;Supported&quot;">​</a></h2><p>Continuously tested, documented, and included within stated compatibility and support boundaries. Merely being technically possible does not make a configuration supported.</p><h2 id="local-network" tabindex="-1">Local Network <a class="header-anchor" href="#local-network" aria-label="Permalink to &quot;Local Network&quot;">​</a></h2><p>The household network from which a user accesses the platform. It reduces exposure but is not automatically considered fully trusted.</p>',31)])])}const m=a(i,[["render",n]]);export{u as __pageData,m as default};
